1629	  function todayStr() {
1630	    const d = new Date();
1631	    const p = (n) => String(n).padStart(2, "0");
1632	    return `${d.getFullYear()}-${p(d.getMonth() + 1)}-${p(d.getDate())}`;
1633	  }
1634	  function dayBounds(dateStr) {
1635	    const [y, m, d] = dateStr.split("-").map(Number);
1636	    const start = Math.floor(new Date(y, m - 1, d, 0, 0, 0, 0).getTime() / 1000);
1637	    const end = Math.floor(new Date(y, m - 1, d + 1, 0, 0, 0, 0).getTime() / 1000);
1638	    return { start, end };
1639	  }
1640	  function shiftDay(dateStr, delta) {
1641	    const [y, m, d] = dateStr.split("-").map(Number);
1642	    const nd = new Date(y, m - 1, d + delta);
1643	    const p = (n) => String(n).padStart(2, "0");
1644	    return `${nd.getFullYear()}-${p(nd.getMonth() + 1)}-${p(nd.getDate())}`;
1645	  }
