1838	  // ---- WebAuthn helpers ----
1839	  const _b64uToBuf = (s) => {
1840	    s = s.replace(/-/g, "+").replace(/_/g, "/");
1841	    s += "=".repeat((4 - (s.length % 4)) % 4);
1842	    const bin = atob(s);
1843	    const buf = new Uint8Array(bin.length);
1844	    for (let i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i);
1845	    return buf.buffer;
1846	  };
1847	  const _bufToB64u = (buf) => {
1848	    const bytes = new Uint8Array(buf);
1849	    let bin = "";
1850	    for (const b of bytes) bin += String.fromCharCode(b);
1851	    return btoa(bin).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
1852	  };
