1854	  async function registerPasskey() {
1855	    if (!hasWebAuthn) { showToast("Bu qurilma passkey'ni qo'llab-quvvatlamaydi", true); return; }
1856	    try {
1857	      const begin = await (await fetch("/api/webauthn/register/begin", { method: "POST" })).json();
1858	      if (begin.detail) throw new Error(begin.detail);
1859	      const o = begin.options;
1860	      o.challenge = _b64uToBuf(o.challenge);
1861	      o.user.id = _b64uToBuf(o.user.id);
1862	      if (o.excludeCredentials) o.excludeCredentials = o.excludeCredentials.map((c) => ({ ...c, id: _b64uToBuf(c.id) }));
1863	      const cred = await navigator.credentials.create({ publicKey: o });
1864	      const payload = {
1865	        id: cred.id,
1866	        rawId: _bufToB64u(cred.rawId),
1867	        type: cred.type,
1868	        response: {
1869	          clientDataJSON: _bufToB64u(cred.response.clientDataJSON),
1870	          attestationObject: _bufToB64u(cred.response.attestationObject),
1871	          transports: cred.response.getTransports ? cred.response.getTransports() : [],
1872	        },
1873	        clientExtensionResults: cred.getClientExtensionResults ? cred.getClientExtensionResults() : {},
1874	      };
1875	      const res = await fetch("/api/webauthn/register/complete", {
1876	        method: "POST",
1877	        headers: { "Content-Type": "application/json" },
1878	        body: JSON.stringify({ challenge_id: begin.challenge_id, credential: payload }),
1879	      });
1880	      const json = await res.json().catch(() => ({}));
1881	      if (!res.ok || !json.ok) throw new Error(json.detail || "xato");
1882	      showToast("Passkey o'rnatildi ✓");
1883	    } catch (e) {
1884	      if (e.name === "NotAllowedError" || e.name === "AbortError") return; // user cancelled
1885	      showToast("Passkey o'rnatib bo'lmadi", true);
1886	    }
